DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_ETL_Cargar_Clientes`()
BEGIN
    -- Desactivar llaves foráneas temporalmente para permitir truncado limpio
    SET FOREIGN_KEY_CHECKS = 0;
    TRUNCATE TABLE Dim_Clientes;
    SET FOREIGN_KEY_CHECKS = 1;

    -- Inserción con transformaciones de calidad de datos
    INSERT INTO Dim_Clientes (IdCliente, Nombre, Email, Telefono, Segmento, Ciudad, Sexo, Edad)
    SELECT 
        -- Tratamiento de ID de cliente
        CASE 
            WHEN TRIM(IdCliente) = '' THEN NULL
            ELSE CAST(TRIM(IdCliente) AS SIGNED)
        END AS IdCliente,
        
        -- Tratamiento de Nombre: Eliminar comillas, espacios al inicio,
        -- resolver caracteres rotos de codificación, y rellenar nulos o vacíos
        COALESCE(
            NULLIF(
                TRIM(BOTH '"' FROM 
                    REPLACE(
                        REPLACE(
                            REPLACE(TRIM(Nombre), 'G├│mez', 'Gómez'),
                            'C├írdenas', 'Cárdenas'
                        ),
                        'R├¡os', 'Ríos'
                    )
                ), 
                ''
            ), 
            'Cliente Sin Nombre'
        ) AS Nombre,
        
        -- Tratamiento de Email: Limpieza y reemplazo de 'NULL' string o vacío
        COALESCE(NULLIF(TRIM(Email), 'NULL'), 'No Registra') AS Email,
        
        -- Tratamiento de Telefono: Limpieza y reemplazo de 'NULL' string o vacío
        COALESCE(NULLIF(TRIM(Telefono), 'NULL'), 'No Registra') AS Telefono,
        
        -- Tratamiento de Segmento: Limpieza y reemplazo de 'NULL' string o vacío
        COALESCE(NULLIF(TRIM(Segmento), 'NULL'), 'General') AS Segmento,
        
        -- Normalización de Ciudades para coincidir con Dim_Tiendas
        CASE 
            WHEN UPPER(TRIM(BOTH '"' FROM TRIM(Ciudad))) LIKE '%BOGOTA%' THEN 'Bogotá'
            WHEN UPPER(TRIM(BOTH '"' FROM TRIM(Ciudad))) LIKE '%MEDELLIN%' THEN 'Medellín'
            WHEN UPPER(TRIM(BOTH '"' FROM TRIM(Ciudad))) LIKE '%CALI%' THEN 'Cali'
            WHEN UPPER(TRIM(BOTH '"' FROM TRIM(Ciudad))) LIKE '%CARTAGENA%' THEN 'Cartagena'
            WHEN UPPER(TRIM(BOTH '"' FROM TRIM(Ciudad))) LIKE '%BUCARAMANGA%' THEN 'Bucaramanga'
            WHEN UPPER(TRIM(BOTH '"' FROM TRIM(Ciudad))) LIKE '%CUCUTA%' THEN 'Cúcuta'
            WHEN UPPER(TRIM(BOTH '"' FROM TRIM(Ciudad))) LIKE '%PEREIRA%' THEN 'Pereira'
            WHEN UPPER(TRIM(BOTH '"' FROM TRIM(Ciudad))) LIKE '%MANIZALES%' THEN 'Manizales'
            WHEN UPPER(TRIM(BOTH '"' FROM TRIM(Ciudad))) LIKE '%IBAGUE%' THEN 'Ibagué'
            WHEN UPPER(TRIM(BOTH '"' FROM TRIM(Ciudad))) LIKE '%BARRANQUILLA%' THEN 'Barranquilla'
            WHEN UPPER(TRIM(BOTH '"' FROM TRIM(Ciudad))) LIKE '%PASTO%' THEN 'Pasto'
            WHEN UPPER(TRIM(BOTH '"' FROM TRIM(Ciudad))) LIKE '%MONTERIA%' THEN 'Montería'
            WHEN UPPER(TRIM(BOTH '"' FROM TRIM(Ciudad))) LIKE '%NEIVA%' THEN 'Neiva'
            ELSE COALESCE(NULLIF(TRIM(BOTH '"' FROM TRIM(Ciudad)), 'NULL'), 'No Registra')
        END AS Ciudad,
        
        -- Tratamiento de Sexo: Limpieza de comillas y nulos
        COALESCE(NULLIF(TRIM(BOTH '"' FROM TRIM(Sexo)), 'NULL'), 'No Registra') AS Sexo,
        
        -- Tratamiento de Edad: Casteo a entero, si viene vacío usar 0
        CASE 
            WHEN TRIM(Edad) = '' OR TRIM(Edad) = 'NULL' OR Edad IS NULL THEN 0
            ELSE CAST(TRIM(Edad) AS SIGNED)
        END AS Edad
    FROM Staging_Clientes
    -- Evitar meter registros si no tienen un ID de cliente válido
    WHERE IdCliente IS NOT NULL AND TRIM(IdCliente) <> '';
    
END ;;
